// data/itineraryData.ts
// All 36 Sawla Tours itineraries — complete individual day-by-day with overnight locations.
//
// V13 note: ItineraryDay and Itinerary both carry a set of *optional* richer fields
// (orientation/experience/paceNotes/fieldNote/accommodation/conditionalNotes/etc. per day;
// journeyNarrative/routeIntelligence/accommodationApproach/extensions/etc. per itinerary).
// Every render site degrades gracefully when these are absent, so itineraries can be
// enriched incrementally without ever showing a broken or half-empty page.

export interface ItineraryExtension { title: string; description: string; bestFor?: string }

export interface ItineraryDay {
  day: number | string
  title: string
  /** Legacy single-paragraph fallback — still rendered as-is when the richer fields below are absent. */
  description: string
  overnight?: string
  /** Set only on the first day of a new route segment — used for jump-nav grouping on itineraries over ~9 days. */
  leg?: string

  // ── V13 premium day-module fields (all optional, fill in as itineraries are enriched) ──
  /** Town/region/site this day is centered on, if distinct from the title. */
  location?: string
  /** 2–3 sentences: the day's purpose, framed simply. */
  orientation?: string
  /** The richer paragraph: what the traveler actually sees, does, and feels. */
  experience?: string
  /** Walking level, road/flight time, altitude, heat, stairs, footwear, terrain — practical realities. */
  paceNotes?: string
  /** A short, specific, grounded local-operator insight — not generic filler. */
  fieldNote?: string
  /** Accommodation STYLE language for this night (e.g. "Heritage hotel in Gondar's old quarter") — not a promised exact property. */
  accommodation?: string
  /** Festival/ceremony/wildlife/road/weather/permit/community-schedule dependencies for this specific day. */
  conditionalNotes?: string
  travelTime?: string
  walkingLevel?: string
  bestFor?: string[]
}

export interface Itinerary {
  slug: string
  styleSlug: string
  name: string
  duration: number
  durationLabel: string
  difficulty: "Easy" | "Moderate" | "Challenging"
  bestMonths: string
  bestFor: string
  overview: string
  highlights: string[]
  days: ItineraryDay[]
  goodToKnow: string[]

  // ── V13 premium page-level fields (all optional) ──
  /** A stronger opening than `overview` alone: why this route exists, who it suits, what makes it meaningful. Rendered alongside overview when present. */
  journeyNarrative?: string
  /** Why the route is sequenced this way — flights, road transfers, altitude progression, market/festival/wildlife timing, pacing logic. */
  routeIntelligence?: string[]
  /** Summary of the accommodation styles used across the journey (derived from the days, written once). */
  accommodationApproach?: string[]
  /** Itinerary-specific inclusions, if they differ from the site-wide defaults. Falls back to DEFAULT_INCLUSIONS when absent. */
  included?: string[]
  /** Itinerary-specific exclusions, if they differ from the site-wide defaults. Falls back to DEFAULT_EXCLUSIONS when absent. */
  excluded?: string[]
  /** Extra itinerary-specific extensions on top of the smart-matched pool (rare — most itineraries just use the pool). */
  extensions?: ItineraryExtension[]
}

// ── V13 shared content pools ──────────────────────────────────────────────────
