export function getItinerary(slug: string): Itinerary | undefined {
  return ITINERARIES.find(i => i.slug === slug)
}

export function getItinerariesByStyle(styleSlug: string): Itinerary[] {
  return ITINERARIES.filter(i => i.styleSlug === styleSlug)
}

// Destination pages → relevant journeys. Matches on the destination's name appearing in
// an itinerary's name/overview/highlights, so it stays accurate as itineraries are edited
// without needing a hand-maintained per-destination list. A handful of remote,
// extension-only destinations (Kafa, Chebera Churchura, Gambella, Kafta Sheraro) genuinely
// have no dedicated itinerary yet — callers should handle an empty result gracefully.
export function getItinerariesForDestination(destSlug: string, destShortName: string, limit = 3): Itinerary[] {
  const needle1 = destShortName.toLowerCase()
  const needle2 = destSlug.replace(/-/g, " ")
  return ITINERARIES
    .filter(itin => {
      const haystack = (itin.name + " " + itin.overview + " " + itin.highlights.join(" ")).toLowerCase()
      return haystack.includes(needle1) || haystack.includes(needle2)
    })
    .slice(0, limit)
}

// Travel-guide articles → relevant journeys. Each guide maps to one or more tour styles
// most relevant to its topic; results are round-robined across styles so a multi-style
// guide (e.g. an inspirational overview) surfaces a diverse set rather than 3 near-duplicates.
const GUIDE_STYLE_MAP: Record<string, string[]> = {
  "when-to-visit-ethiopia":            ["historic-cultural-ethiopia-tours", "ethiopia-festival-tours"],
  "ethiopia-travel-circuits":          ["historic-cultural-ethiopia-tours"],
  "how-to-plan-your-trip":             ["historic-cultural-ethiopia-tours"],
  "how-to-get-to-ethiopia":            ["addis-ababa-day-tours"],
  "ethiopia-domestic-flights":         ["ethiopia-adventure-tours"],
  "ethiopia-visa-guide":               ["addis-ababa-day-tours"],
  "health-safety-ethiopia":            ["ethiopia-adventure-tours"],
  "safety-in-ethiopia":                ["ethiopia-adventure-tours"],
  "what-to-pack-for-ethiopia":         ["ethiopia-adventure-tours", "ethiopia-wildlife-tours"],
  "ethiopia-travel-costs":             ["historic-cultural-ethiopia-tours"],
  "hotels-lodges-ethiopia":            ["historic-cultural-ethiopia-tours"],
  "ethiopia-safaris":                  ["ethiopia-wildlife-tours"],
  "popular-wildlife-ethiopia":         ["ethiopia-wildlife-tours"],
  "ethiopia-birding-guide":            ["ethiopia-birdwatching-tours"],
  "ethiopia-photography-guide":        ["ethiopia-photography-tours"],
  "drone-binocular-permits-ethiopia":  ["ethiopia-photography-tours", "ethiopia-birdwatching-tours"],
  "ethiopian-food-coffee":             ["ethiopia-special-interest-tours"],
  "ethiopia-festival-calendar":        ["ethiopia-festival-tours"],
  "cultural-etiquette-ethiopia":       ["omo-valley-cultural-tours", "historic-cultural-ethiopia-tours"],
  "responsible-travel-ethiopia":       ["omo-valley-cultural-tours"],
  "mobile-camping-ethiopia":           ["ethiopia-adventure-tours"],
  "general-travel-tips":               ["historic-cultural-ethiopia-tours"],
  "why-visit-ethiopia":                ["historic-cultural-ethiopia-tours", "omo-valley-cultural-tours", "ethiopia-wildlife-tours"],
}

export function getItinerariesForGuide(guideSlug: string, limit = 3): Itinerary[] {
  const styles = GUIDE_STYLE_MAP[guideSlug] ?? ["historic-cultural-ethiopia-tours"]
  let pools = styles.map(s => getItinerariesByStyle(s))
  // Two styles (special-interest, Addis day tours) legitimately have no itineraries;
  // guides mapped only to those still deserve journey links rather than an empty sidebar.
  if (pools.every(p => p.length === 0)) pools = [getItinerariesByStyle("historic-cultural-ethiopia-tours")]
  const seen = new Set<string>()
  const result: Itinerary[] = []
  for (let round = 0; result.length < limit; round++) {
    let addedThisRound = false
    for (const pool of pools) {
      const itin = pool[round]
      if (itin && !seen.has(itin.slug)) {
        seen.add(itin.slug)
        result.push(itin)
        addedThisRound = true
        if (result.length >= limit) break
      }
    }
    if (!addedThisRound) break
  }
  return result
}

// Derived (not authored) — "Conditional" once at least ~a third of days carry a real
// access/seasonal/permission caveat, so this differentiates (nearly every honest Ethiopia
// itinerary has at least one caveat somewhere) and stays accurate as content evolves.
export function getOperatingStatus(itin: Itinerary): "Standard" | "Conditional" {
  const conditionalDays = itin.days.filter(d => d.conditionalNotes).length
  return conditionalDays / itin.days.length >= 0.35 ? "Conditional" : "Standard"
}

// Same signal, reused: itineraries where logistics (not hotel choice) drive the price
// get the remote-expedition pricing note instead of the standard tailor-made one.
export function getPricingNote(itin: Itinerary): string {
  return getOperatingStatus(itin) === "Conditional" ? PRICING_NOTE_REMOTE : PRICING_NOTE_STANDARD
}

// Smart-matches 2–3 relevant extensions from the shared pool by style relevance,
// excluding any extension whose region is already the subject of this itinerary
// (e.g. no "Danakil Extension" suggested on a Danakil itinerary itself).
// Itinerary-specific `extensions` (rare) are always included first.
export function getRelevantExtensions(itin: Itinerary, limit = 3): ItineraryExtension[] {
  const nameLower = itin.name.toLowerCase()
  const selfRegionWords = ["danakil", "omo", "bale", "simien", "tigray", "gambella", "harar", "coffee"]
  const mentionsOwnRegion = (title: string) =>
    selfRegionWords.some(w => title.toLowerCase().includes(w) && nameLower.includes(w))

  const fromPool = EXTENSIONS_POOL
    .filter(e => e.keywords.some(k => itin.styleSlug.includes(k)))
    .filter(e => !mentionsOwnRegion(e.title))
    .map(({ keywords: _keywords, ...rest }) => rest)

  const custom = itin.extensions ?? []
  const combined = [...custom, ...fromPool]

  // De-duplicate by title, keep order (custom first)
  const seen = new Set<string>()
  const deduped = combined.filter(e => (seen.has(e.title) ? false : (seen.add(e.title), true)))

  return deduped.slice(0, limit)
}